### 방안 C: Redis 캐시 적용

**파일 위치: `app/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt`**

```kotlin
// After - Redis 캐시 + 최적화된 쿼리
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    companion object {
        // 캐시 키 패턴
        private const val FOLLOWING_LIST_KEY = "follow:following:{userId}"
        private const val FOLLOWER_LIST_KEY  = "follow:follower:{userId}"
        // TTL: 팔로우는 변경이 드물므로 5분 캐시
        private val FOLLOW_LIST_TTL = Duration.ofMinutes(5)
    }

    fun getFollowingList(userId: String): List<FollowUserProjection> {
        val cacheKey = FOLLOWING_LIST_KEY.replace("{userId}", userId)

        // 1. 캐시 히트 시 즉시 반환
        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) {
            @Suppress("UNCHECKED_CAST")
            return cached as List<FollowUserProjection>
        }

        // 2. 캐시 미스 시 DB 조회 (이미 Fetch Join으로 최적화됨)
        val result = followRepository.findFollowingListWithUser(userId)

        // 3. 결과를 캐시에 저장
        redisTemplate.opsForValue().set(cacheKey, result, FOLLOW_LIST_TTL)

        return result
    }

    fun follow(followerId: String, followingId: String) {
        val entity = FollowEntity(followerId = followerId, followingId = followingId)
        followRepository.save(entity)

        // 4. 팔로우/언팔로우 시 캐시 무효화
        invalidateFollowCache(followerId, followingId)
    }

    fun unfollow(followerId: String, followingId: String) {
        followRepository
            .findByFollowerIdAndFollowingId(followerId, followingId)
            ?.let { followRepository.delete(it) }

        invalidateFollowCache(followerId, followingId)
    }

    private fun invalidateFollowCache(followerId: String, followingId: String) {
        redisTemplate.delete(FOLLOWING_LIST_KEY.replace("{userId}", followerId))
        redisTemplate.delete(FOLLOWER_LIST_KEY.replace("{userId}", followingId))
    }
}
```

