### 방안 D: @Cacheable 어노테이션 방식 (Spring Cache 추상화)

캐시 로직을 서비스에서 분리하고 싶다면 Spring Cache를 활용합니다.

**파일 위치: `app/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt`**

```kotlin
@Service
class FollowService(
    private val followRepository: FollowRepository,
) {
    // 캐시 적용 - TTL은 CacheConfig에서 설정
    @Cacheable(cacheNames = ["follow:following"], key = "#userId")
    fun getFollowingList(userId: String): List<FollowUserProjection> {
        return followRepository.findFollowingListWithUser(userId)
    }

    @Cacheable(cacheNames = ["follow:follower"], key = "#userId")
    fun getFollowerList(userId: String): List<FollowUserProjection> {
        return followRepository.findFollowerListWithUser(userId)
    }

    @CacheEvict(
        cacheNames = ["follow:following", "follow:follower"],
        allEntries = false,
        key = "#followerId"  // 팔로잉 목록 무효화
    )
    fun follow(followerId: String, followingId: String) {
        followRepository.save(FollowEntity(followerId = followerId, followingId = followingId))
        // followingId의 팔로워 목록도 별도 무효화 필요
    }
}
```

**파일 위치: `app/src/main/kotlin/com/maum/backend/config/CacheConfig.kt`**

```kotlin
@Configuration
@EnableCaching
class CacheConfig(
    private val redisConnectionFactory: RedisConnectionFactory,
) {
    @Bean
    fun cacheManager(): CacheManager {
        val objectMapper = ObjectMapper().apply {
            registerKotlinModule()
            registerModule(JavaTimeModule())
            disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS)
        }

        val serializer = GenericJackson2JsonRedisSerializer(objectMapper)

        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .entryTtl(Duration.ofMinutes(5))
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(serializer)
            )

        val cacheConfigs = mapOf(
            "follow:following" to defaultConfig.entryTtl(Duration.ofMinutes(5)),
            "follow:follower"  to defaultConfig.entryTtl(Duration.ofMinutes(5)),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(defaultConfig)
            .withInitialCacheConfigurations(cacheConfigs)
            .build()
    }
}
